	(1, 1, 'belfoods.com PT Sreeya Sewu Indonesia, Tbk', 'belfoodscom-pt-sreeya-sewu-indonesia-tbk.html', 'belfoods.com PT Sreeya Sewu Indonesia, Tbk', '', '', '', '', '', '', '<p style="text-align: center;" data-mce-style="text-align: center;"><span style="font-size: 14pt;" data-mce-style="font-size: 14pt;"><strong>Royal by Belfoods</strong> consistently innovates by presenting high-quality premium products aligned with the latest trends.</span><br><span style="font-size: 14pt;" data-mce-style="font-size: 14pt;">We believe in delivering a more premium and high-quality experience to consumers.</span><br><span style="font-size: 14pt;" data-mce-style="font-size: 14pt;">Therefore, Royal by Belfoods is increasingly recognized as a trusted brand and delivers </span><br><span style="font-size: 14pt;" data-mce-style="font-size: 14pt;">high-quality products that stay on trend. <strong>Enjoy the premium taste and quality of our products!</strong></span></p>', '', '2019-01-01 00:00:00', '', 'Belfoods presents high-quality products as delicious as homemade cooking, Enjoy the premium taste and quality of our products!', '', 1, 999, 1, 'admin', '2026-03-03 13:56:09', '2026-03-03 13:56:09'),
