	(22, 8, 'Royal Smoked Chicken Sausage', 'royal-smoked-chicken-sausage.html', 'Royal Smoked Chicken Sausage', '', 'Net Weight: 200gr', '', '', '', '', '<p><span style="color: rgb(0, 0, 0);" data-mce-style="color: #000000;"><b>Royal by Belfoods Chicken Sausage Asap</b></span><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> brings a favorite serving for the whole family. Diolah dari daging ayam berkualitas dengan proses pengasapan sehingga menghasilkan aroma yang khas, </span><span style="color: rgb(0, 0, 0);" data-mce-style="color: #000000;"><b>Royal by Belfoods Chicken Sausage Asap</b></span><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> hadirkan keceriaan di your home.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/royal/ROYAL-SosisSmokedChicken.png', '', '', 1, 11, 1, 'admin', '2026-03-09 14:21:31', '2026-03-09 14:21:31'),
