	(25, 8, 'Royal Fry N Shake', 'royal-fry-n-shake.html', 'Royal Fry N Shake', '', 'Net Weight: 250gr', '', '', '', '', '<p><span style="font-weight: 400;" data-mce-style="font-weight: 400;">Experience the premium deliciousness of </span><span style="color: rgb(0, 0, 0);" data-mce-style="color: #000000;"><b>Royal by Belfoods Fry N Shake</b></span><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> dengan bumbu rasa Barbeque! Made from kentang pilihan dengan tekstur yang renyah dan lembut didalam. Sajian lezat yang cocok untuk camilan. </span><span style="color: rgb(0, 0, 0);" data-mce-style="color: #000000;"><b>Royal by Belfoods Fry N Shake</b></span><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> menjanjikan kelezatan di setiap gigitannya!</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/royal/ROYAL-FryNShake.png', '', '', 1, 12, 1, 'admin', '2026-03-09 14:21:34', '2026-03-09 14:21:34'),
	(26, 8, 'Royal Cordon Bleu', 'royal-cordon-bleu.html', 'Royal Cordon Bleu', '', 'Net Weight: 250gr', '', '', '', '', '<p><b><span style="color: rgb(0, 0, 0);" data-mce-style="color: #000000;">Royal by Belfoods Ayam Gulung Isi Keju</span> </b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">menghadirkan sajian berkualitas on your dining table. Saatnya membawa cita rasa ala Perancis ke your home dengan kelezatan dagingayam asap dan keju di dalam gulungan dada ayam yang dibalut tepung roti renyah.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/royal/ROYAL-CordonBleu.png', '', '', 1, 8, 1, 'admin', '2026-03-09 14:21:36', '2026-03-09 14:21:36'),
