	(28, 9, 'Belfoods French Fries Shoestring', 'belfoods-french-fries-shoestring.html', 'Belfoods French Fries Shoestring', '', 'Net Weight: 500gr', '', '', '', '', '<p><b>Belfoods Frozen French Fries</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> menghadirkan sajian favorit bagi seluruh keluarga. Dibuat dengan kentang pilihan, </span><b>Belfoods Frozen French Fries</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> cocok untuk menjadi cemilan dan hadirkan keceriaan di segala suasana.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-Kentang-GorengShoestring-500gr.png', '', '', 1, 13, 1, 'admin', '2026-03-09 14:37:33', '2026-03-09 14:37:33'),
