	(31, 9, 'Belfoods Chicken Cocktail', 'belfoods-chicken-cocktail.html', 'Belfoods Chicken Cocktail', '', 'Net Weight: 400gr', '', '', '', '', '<p><b>Belfoods Chicken Sausage Cocktail</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> dibuat dengan daging ayam pilihan. </span><b>Belfoods Chicken Sausage Cocktail</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> telah dimasak for your convenience. </span><b>Belfoods Chicken Sausage Cocktail</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> lezat untuk dihidangkan sebagai menu utama, makanan kecil maupun hidangan pesta.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-ChickenCocktail-400gr.png', '', '', 1, 16, 1, 'admin', '2026-03-09 14:37:38', '2026-03-09 14:37:38'),
