	(35, 9, 'Belfoods Chicken Meatball', 'belfoods-chicken-meatball.html', 'Belfoods Chicken Meatball', '', 'Net Weight: 100gr ', '', '', '', '', '<p><b>Belfoods Chicken Meatballs</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> menghadirkan sajian favorit bagi seluruh keluarga. Diracik dan diolah secara spesial menjadikan rasa baksonya begitu sedap pada setiap gigitan. </span><b>Belfoods Chicken Meatballs</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> dapat dinikmati sebagai hidangan bakso berkuah maupun dimasak sebagai bahan pelengkap masakan lainnya. Hadirkan keceriaan di rumah bersama </span><b>Belfoods Chicken Meatballs</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-BaksoAyam-100grpng.png', '', '', 1, 18, 1, 'admin', '2026-03-09 14:37:47', '2026-03-09 14:37:47'),
	(36, 9, 'Belfoods Crispy Chicken Burger', 'belfoods-crispy-chicken-burger.html', 'Belfoods Crispy Chicken Burger', '', 'Net Weight: 315gr', '', '', '', '', '<p><b>Belfoods Burger Ayam Renyah</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> Menghadirkan sajian favorite bagi seluruh keluarga.Dibuat dengan daging ayam pilihan yang dilapisi tepung roti yang gurih dan renyah. </span><b>Belfoods Burger Ayam Renyah</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> hadirkan keceriaan di setiap suasana keluarga Anda.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-CrispyChickenBurger-450gr.png', '', '', 1, 15, 1, 'admin', '2026-03-09 14:37:49', '2026-03-09 14:37:49'),
	(37, 9, 'Belfoods Chicken Nugget BTS', 'belfoods-chicken-nugget-bts.html', 'Belfoods Chicken Nugget BTS', '', 'Net Weight: 450gr ', '', '', '', '', '<p><b>Belfoods Chicken Nugget "Be The Star (BTS)"</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">menghadirkan sajian favorit bagi seluruh keluarga. Dibuat dengan daging ayam pilihan menggunakan bumbu pizza, dibalut dengan tepung roti yang renyah dan dibentuk menarik yaitu Bintang dan Hati serta mengandung Kalsium membantu dalam pembentukan dan mempertahankan kepadatan tulang dan gigi. Membuat </span><b>Belfoods Chicken Nugget "Be The Star (BTS)" </b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">selalu dapat menceriakan meja makan anda.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-NuggetBTS-450gr.png', '', '', 1, 8, 1, 'admin', '2026-03-09 14:37:51', '2026-03-09 14:37:51'),
