	(41, 11, 'Bonanza Bakso Sapi Gold', 'bonanza-bakso-sapi-gold.html', 'Bonanza Bakso Sapi Gold', '', 'Net Weight: 180gr  |  500gr  ', '', '', '', '', '<p><b>Bonanza Meatballs Sapi </b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">dibuat dengan daging sapi dengan racikan bumbu pilihan. Menghadirkan cita rasa khas bakso sapi dengan tekstur kenyal dan rasa yang gurih, </span><b>Bonanza Meatballs Sapi</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> selalu menjadi pilihan keluarga Indonesia.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/bonanza/Bonanza-Gold-500g.png', '', '', 1, 1, 1, 'admin', '2026-03-09 15:17:48', '2026-03-09 15:17:48'),
