	(47, 2, '<b>Kentang Panggang Cheezy Bites</b>', 'kentang-panggang-cheezy-bites.html', '<b>Kentang Panggang Cheezy Bites</b>', '', '', '', '', '', '', '<p><span>kreasi lezatnya cinta ibu, untuk kerluarga dalam hidangan&nbsp;Kentang Panggang Cheezy Bites</span></p><h5>Ingredients</h5><p>1 bungkus<span>&nbsp;</span><a href="http://manifesto.co.id/clients/belfoods//products/royal/cheezy-bites/#sthash.inim2Ny8.dpbs" data-mce-href="http://manifesto.co.id/clients/belfoods//products/royal/cheezy-bites/#sthash.inim2Ny8.dpbs">Belfoods Royal Cheezy Bites</a>, goreng dan tiriskan<br>400 gr kentang kukus,haluskan<br>1 sendok makan mentega<br>100 gr keju parut<br>50 ml krim kental<br>Merica dan garam secukupnya<br>1 sendok teh peterseli cincang</p><h5>Instructions</h5><p>1.Campur kentang dengan mentega, krim kental, setengah bagian keju, peterseli, merica, dan garam, aduk rata.<br>?2.Susun dalam mangkuk tahan panas lalu beri Belfoods Royal Cheezy Bitesdi atasnya, taburi dengan sisa keju parut. Panggang sebentar hingga keju berubah warna dan harum.<br>?3. Angkat dan sajikan panas dengan saus sambal</p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/wp-content/uploads/2013/06/kentang-panggang-370x1901.jpg', '', '', 1, 7, 0, 'admin', '2026-03-09 15:27:54', '2026-03-18 13:56:23'),
	(48, 2, 'New 09 Mar 2026, 15:28', 'new-09032026152808.html', '', '', '', '', '', '', '', '', '', '2019-01-01 00:00:00', '', '', '', 1, 999, 0, 'admin', '2026-03-09 15:28:08', '2026-03-10 14:14:34'),
	(49, 2, 'Tumis Mangga Spicy Wings', 'tumis-mangga-spicy-wings.html', 'Tumis Mangga Spicy Wings', '', '', '', '', '', '', '<div class="span4 ingredient"><h5>ngredients</h5><ul><li>1 bungkus Belfoods Favorite Spicy Wings, goreng</li><li>3 sendok makan minyak goreng</li><li>3 buah cabai merah besar, iris serong</li><li>3 buah cabai hijau besar, iris serong</li><li>6 butir bawang merah, iris halus</li><li>3 siung bawang putih, iris halus</li><li>1 buah tomat, potong dadu</li><li>1 ruas jari jahe, memarkan</li><li>2 lembar daun jeruk</li><li>100 ml air</li><li>2 buah mangga muda, iris korek api</li><li>Garam dan gula pasir</li></ul><p>&nbsp;</p></div><div class="span4 instructions"><h5>Instructions</h5><ul><li>Panaskan minyak goreng lalu tumis semua bumbu iris hingga harus. Tuang air, garam, dan gula pasir, aduk rata.</li><li>Masukkan Belfoods Favorite Spicy Wings, garam, dan gula pasir, aduk rata lalu masukkan mangga muda sesaat sebelum diangkat.</li></ul></div>', '', '2019-01-01 00:00:00', 'https://belfoods.com/wp-content/uploads/2013/12/Tumis-Mangga-Spicy-Wings.jpg', '', '', 1, 999, 0, 'admin', '2026-03-09 15:28:13', '2026-03-16 15:40:37'),
	(50, 2, 'Ingredients 1 bungkus Belfoods Favorite Spicy Wings, goreng 3 sendok makan minyak goreng 3 buah cabai merah besar, iris serong 3 buah cabai hijau besar, iris serong 6 butir bawang merah, iris halus 3 siung bawang putih, iris halus 1 buah tomat, poton', 'ingredients-1-bungkus-belfoods-favorite-spicy-wings-goreng-3-sendok-makan-minyak-goreng-3-buah-cabai-merah-besar-iris-serong-3-buah-cabai-hijau-besar-iris-serong-6-butir-bawang-merah-iris-halus-3-siung-bawang-putih-iris-halus-1-buah-tomat-potong-dadu', 'Ingredients 1 bungkus Belfoods Favorite Spicy Wings, goreng 3 sendok makan minyak goreng 3 buah cabai merah besar, iris serong 3 buah cabai hijau besar, iris serong 6 butir bawang merah, iris halus 3 siung bawang putih, iris halus 1 buah tomat, poton', '', '', '', '', '', '', '<p>kreasi lezatnya cinta ibu, untuk kerluarga dalam hidangan&nbsp;Crepes Lipat Nugget Safari</p><div class="row"><div class="span4 ingredient"><h5>Ingredients</h5><p>150 gr terigu<br>275 ml susu cair<br>50 gr gula halus<br>60 gr mentega cair<br>ÃÂ½ sendok teh baking powder<br>2 butir telur<br>1 bungkus<span>&nbsp;</span><a href="http://manifesto.co.id/clients/belfoods//products/favorite/chicken-nugget-safari/#sthash.9ivkI5pH.dpbs" data-mce-href="http://manifesto.co.id/clients/belfoods//products/favorite/chicken-nugget-safari/#sthash.9ivkI5pH.dpbs">Belfoods Favorite Safari</a>, goreng<br>100 gr selada<br>1 buah wortel, iris korek api,rebus<br>50 ml mayones<br>3 sendok makan saus tomat<br>2 sendok makan saus sambal</p></div><div class="span4 instructions"><h5>Instructions</h5><p>Crepes:</p><p>1. Campur tepung terigu,susu cair, gula halus, mentega cair, baking powder, dan telur,aduk hingga rata.<br>2. Panaskan pan datar lalu buat dadar tipis,lakukan hal yang sama hingga bahan habis.<br>3. Siapkan satu lembar crepes,isi dengan selada, wortel, dan Belfoods Favorite Safari.<br>4. Tambahkan dengan mayones,saus tomat, dan saus sambal.</p></div></div>', '', '2019-01-01 00:00:00', 'https://belfoods.com/wp-content/uploads/2013/06/creppes-lipat-370x1903.jpg', '', '', 1, 999, 0, 'admin', '2026-03-09 15:28:16', '2026-03-09 16:47:22'),
	(51, 2, '<b>Mushroom Soup With Cheese Sausages</b>', 'mushroom-soup-with-cheese-sausages.html', '<b>Mushroom Soup With Cheese Sausages</b>', '', '', '', '', '', '', '<p><em>For 4 servings</em><br></p><p><span style="font-size: 14pt; background-color: rgb(241, 196, 15);" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: rgb(0, 0, 0);" data-mce-style="color: #000000;">&nbsp;Ingredients : </span>&nbsp;</strong></span></p><ul><li>2 sdm mentega/margarin 30 gr bawang bombai, cincang</li><li>3 siung bawang putih, cincang</li><li>100 gr jamur kancing segar, iris tipis</li><li>2 sdm tepung terigu</li><li>300 ml kaldu ayam</li><li>200 ml susu cair</li><li>4 buah <strong>ROYAL CHEESE FRANKFURTER</strong>, iris sesuai selera</li><li>1 sdm bumbu Itali bubuk</li><li>1 sdt garam</li><li>ÃÂ½ sdt merica bubuk</li><li>2 sdm seledri cincang<br></li></ul><p><span style="font-size: 14pt; background-color: rgb(241, 196, 15);" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: rgb(0, 0, 0);" data-mce-style="color: #000000;">&nbsp;How to Make :</span>&nbsp;</strong></span></p><ol><li>Panaskan mentega/margarin, tumis bawang bombai cincang dan bawang putih cincang hingga harum. Masukkan jamur kancing, tumis sebentar.</li><li>Tambahkan tepung terigu, aduk rata. Tuangkan kaldu ayam dan susu cair. Aduk sampai kental.</li><li>Masukkan <strong>ROYAL CHEESE FRANKFURTER</strong>, bumbui dengan bumbu Itali, garam, dan merica bubuk, garam, dan gula pasir. Masak hingga mendidih, angkat.</li><li>Sajikan sup selagi hangat dengan taburan seledri cincang.</li></ol>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/content/Foto-Resep-Mushroom-Soup2.jpg', '', '', 1, 5, 1, 'admin', '2026-03-09 15:28:18', '2026-03-09 15:28:18'),
	(52, 2, '<b>Chicken Karaage With Honey Lemon Sauce</b>', 'chicken-karaage-with-honey-lemon-sauce.html', '<b>Chicken Karaage With Honey Lemon Sauce</b>', '', '', '', '', '', '', '<p><em>For 4 servings</em></p><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;Ingredients : </span>&nbsp;</strong></span></p><ul><li><span>500 gr <strong>ROYAL CRISPY KARAAGE</strong></span></li><li><span>Minyak goreng secukupnya</span></li><li><span>2 sdm daun bawang iris halus</span><span><br><br></span><span>Honey Lemon Sauce</span>&nbsp;:</li><li><span>2 sdm margarin</span></li><li><span>3 siung bawang putih, cincang</span></li><li><span>2 cm jahe muda, iris panjang</span></li><li><span>250 ml kaldu ayam/air</span></li><li><span>2 sdm madu</span></li><li><span>ÃÂ¼ sdt merica bubuk</span></li><li><span>ÃÂ½ sdt garam</span></li><li><span>1 sdm tepung maizena, larutkan dengan sedikit air</span></li></ul><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;How to Make :</span>&nbsp;</strong></span></p><ol><li>Goreng <strong>ROYAL CRISPY KARAAGE</strong> dengan minyak goreng panas hingga kuning keemasan. Angkat dan tiriskan. Sisihkan.</li><li><span>Saus madu lemon : Panaskan margarin, tumis bawang putih dan jahe muda hingga harum. Tambahkan kaldu ayam/air, madu, merica bubuk, garam, dan larutan maizena. Masak sambil aduk hingga saus kental.</span></li><li>Masukkan chicken karage goreng dan daun bawang. Aduk hingga chicken karaage rata dengan saus.<br></li><li><span>Angkat dan sajikan.</span></li></ol>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/content/Foto-Resep-KaraageLemon.jpg', '', '', 1, 4, 1, 'admin', '2026-03-09 15:28:20', '2026-03-09 15:28:20'),
	(53, 2, '<b>Caesar Salad Golden Fillet</b>', 'caesar-salad-golden-fillet.html', '<b>Caesar Salad Golden Fillet</b>', '', '', '', '', '', '', '<p><em>For 4 servings</em></p><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;Ingredients : </span>&nbsp;</strong></span></p><ul><li><span>500 gr <strong>ROYAL GOLDEN FILLET</strong></span></li><li><span>10 buah tomat ceri, belah dua</span></li><li><span>5 lembar daun selada, iris kasar</span></li><li><span>2 sdm parmesan bubuk<br><br></span>Dressing :</li><li><span>150 ml minyak sayur</span></li><li><span>1 ÃÂ½ sdm air jeruk lemon</span></li><li><span>1/8 sdt garam</span></li><li><span>1/8 sdt merica hitam tumbuk kasar</span></li><li><span>1 sdt gula pasir</span></li></ul><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;How to Make :</span>&nbsp;</strong></span></p><ol><li>Goreng <strong>ROYAL GOLDEN FILLET</strong> dalam minyak goreng panas hingga kuning keemasn. Angkat dan tiriskan, kemudian potong sesuai selera.<br></li><li>Dressing: kocok minyak sayur, air jeruk lemon, garam, merica dan gula pasir dengan whisk hingga kental dan putih.<br></li><li>Tata tomat ceri dan daun selada dalam piring saji. Tambahkan <strong>ROYAL GOLDEN FILLET</strong>, siram atasnya dengan dressing dan taburi keju parmesan. Sajikan segera.</li></ol>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/content/Foto-Resep-CaesarGoldenFillet1.jpg', '', '', 1, 2, 1, 'admin', '2026-03-09 15:28:21', '2026-03-09 15:28:21'),
	(54, 2, '<b>Penne Cheezy Bites</b>', 'penne-cheezy-bites.html', '<b>Penne Cheezy Bites</b>', '', '', '', '', '', '', '<p>For 4 servings<br>Bahan:<br>500 gr BELFOODS ROYAL CHEEZY BITES<br>Minyak goreng secukupnya</p><p>2 sdm margarin<br>30 gr bawang bombai, cincang<br>2 siung bawang putih, cincang<br>3 buah tomat merah, kupas, cincang<br>200 ml kaldu ayam.<br>ÃÂ½ sdt oregano bubuk<br>3 sdm saus tomat<br>ÃÂ¼ sdt merica<br>ÃÂ½ sdt garam<br>400 gr penne yang sudah direbus matang sedang (al dente)<br>50 gr keju cheddar parut</p><p>How to Make</p><ul><li>Goreng BELFOODS ROYAL CHEEZY BITES dengan minyak goreng panas hingga kuning keemasan. Angkat dan tiriskan.</li><li>Panaskan margarin, tumis bawang bombai dan bawang putih hingga harum. Masukkan tomat cincang, kaldu, oregano, saus tomat, merica, dan garam. Masak hingga saus kental.</li><li>Masukkan penne dan BELFOODS ROYAL CHEEZY BITES. Aduk hingga rata dengan saus.</li><li>Sajikan dengan taburan keju cheddar parut.</li></ul>', '', '2019-01-01 00:00:00', 'https://belfoods.com/wp-content/uploads/2019/10/PENNE-CHEEZY-BITES.jpg', '', '', 1, 3, 0, 'admin', '2026-03-09 15:28:23', '2026-03-18 13:48:54'),
	(55, 2, '<b>Honey Garlic With Sausages</b>', 'honey-garlic-with-sausages.html', '<b>Honey Garlic With Sausages</b>', '', '', '', '', '', '', '<p><em>For 4 servings</em></p><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;Ingredients : </span>&nbsp;</strong></span></p><ul><li><span>3 sdm margarin</span></li><li>30 gr bawang bombai, iris tipis</li><li><span>3 siung bawang putih, cincang</span></li><li><span>100 gr kacang panjang, potong 5 cm</span></li><li><span>250 gr brokoli, potong-potong</span></li><li><span>2 buah cabai merah, iris panjang</span></li><li><span>4 buah <strong>ROYAL BEEF FRANKFURTER</strong>, tambah sedikit keratin</span></li><li><span>2 ÃÂ½ sdm madu</span></li><li><span>1 sdm kecap asin</span></li><li><span>ÃÂ½ sdt merica hitam tumbuk kasar</span></li><li><span>ÃÂ¼ sdt garam</span></li><li><span>100 gr kacang panjang, potong 5 cm</span></li></ul><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;How to Make :</span>&nbsp;</strong></span></p><ol><li>Panaskan margarin, tumis bawang bombai dan bawang putih hingga harum. Masukkan kacang panjang, brokoli, dan cabai merah yang diiris panjang, tumis sebentar hingga sayuran mulai matang.<br></li><li>Masukkan <strong>ROYAL BEEF FRANKFURTER</strong>, tumis hingga keratin sosis merekah.<br></li><li>Bumbui dengan madu, kecap asin, merica hitam, dan garam. Aduk rata.<br></li><li>Angkat dan sajikan hangat.<br></li></ol>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/content/Foto-Resep-Honey-Garlic1.jpg', '', '', 1, 1, 1, 'admin', '2026-03-09 15:28:34', '2026-03-09 15:28:34'),
	(56, 2, '<b>Bento Drumies Sushi Rice</b>', 'bento-drumies-sushi-rice.html', '<b>Bento Drumies Sushi Rice</b>', '', '', '', '', '', '', '<p><em>For 4 servings</em></p><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;Ingredients : </span>&nbsp;</strong></span></p><ul><li><span>470 gr <strong>ROYAL CHICKEN NUGGET DRUMMIES</strong></span></li><li><span>Minyak goreng secukupnya</span></li><li style="line-height: 1;" data-mce-style="line-height: 1;"><span>4 lembar nori, potong 5 cm</span><span><br><br>Butter Rice :<br></span></li><li><span>3 sdm mentega</span></li><li><span>3 siung bawang putih, cincang</span></li><li><span>1 butir telur, kocok</span></li><li><span>500 gr nasi pulen</span></li><li><span>ÃÂ½ sdt garam</span></li><li><span>ÃÂ¼ sdt merica bubuk</span></li></ul><p><span style="font-size: 14pt; background-color: #f1c40f;" data-mce-style="font-size: 14pt; background-color: #f1c40f;"><strong><span style="color: #000000;" data-mce-style="color: #000000;">&nbsp;How to Make :</span>&nbsp;</strong></span></p><ol><li>Goreng <span><strong>ROYAL CHICKEN NUGGET DRUMMIES</strong></span> dengan minyak goreng panas hingga kuning keemasan. Angkat dan tiriskan.<br></li><li>Butter Rice: Panaskan mentega, tumis bawang putih cincang hingga harum. Masukkan telur kocok, aduk rata hingga bergumpal. Masukkan nasi, garam, dan merica bubuk. Aduk hungga nasi rata dengan bumbu. Angkat.<br></li><li>Siapkan selembar nori, ratakan butter rice di atasnya. Taruh <span><strong>ROYAL CHICKEN NUGGET DRUMMIES</strong></span> di bagian tengah, lalu gulung sushi sambil padatkan.<br></li><li>Sajikan dan tata dalam boks bento bersama sayuran dan buah segar sesuai selera.<br></li></ol>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/content/Foto-Resep-Bento1.jpg', '', '', 1, 3, 1, 'admin', '2026-03-09 15:28:36', '2026-03-09 15:28:36'),
	(57, 12, 'Ayam Nanas ETC Opor Ayam', 'ayam-nanas-etc-opor-ayam.html', 'Ayam Nanas ETC Opor Ayam', '', 'Net Weight: 250gr', '', '', '', '', '<p><span style="font-weight: 400;" data-mce-style="font-weight: 400;">Seri Nusantara hadir sebagai pilihan andalan keluarga, menghadirkan Rasa Warisan Otentik yang kaya cita rasa. Dirancang untuk mendukung kepraktisan memasak dengan bahan terpilih, dan memperkuat ikatan keluarga melalui rasa khas Nusantara.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/ayam-nanas/AyamNanas-EasyToCook-OporAyam.png?_t=1773300336', '', '', 1, 2, 1, 'admin', '2026-03-10 18:19:38', '2026-03-10 18:19:38'),
	(58, 12, 'Ayam Nanas ETC Rendang Ayam', 'ayam-nanas-etc-rendang-ayam.html', 'Ayam Nanas ETC Rendang Ayam', '', 'Net Weight: 200gr', '', '', '', '', '<p><span style="font-weight: 400;" data-mce-style="font-weight: 400;">Seri Nusantara hadir sebagai pilihan andalan keluarga, menghadirkan Rasa Warisan Otentik yang kaya cita rasa. Dirancang untuk mendukung kepraktisan memasak dengan bahan terpilih, dan memperkuat ikatan keluarga melalui rasa khas Nusantara.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/ayam-nanas/AyamNanas-EasyToCook-RendangAyam.png?_t=1773300338', '', '', 1, 1, 1, 'admin', '2026-03-10 18:19:39', '2026-03-10 18:19:39'),
	(59, 12, 'Ayam Nanas ETC Chicken Teriyaki', 'ayam-nanas-etc-chicken-teriyaki.html', 'Ayam Nanas ETC Chicken Teriyaki', '', 'Net Weight: 250gr', '', '', '', '', '<p><span style="font-weight: 400;" data-mce-style="font-weight: 400;">Made from Ayam Nanas dan dibumbui dengan saus teriyaki yang khas membuat </span><b>Ayam Nanas Chicken Teriyaki</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> menjadi pilihan yang lezat dan praktis untuk keluarga.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/ayam-nanas/AyamNanas-EasyToCook-Teriyaki.png?_t=1773300339', '', '', 1, 4, 1, 'admin', '2026-03-10 18:19:40', '2026-03-10 18:19:40'),
	(60, 12, 'Ayam Nanas ETC Chicken Katsu', 'ayam-nanas-etc-chicken-katsu.html', 'Ayam Nanas ETC Chicken Katsu', '', 'Net Weight: 250gr', '', '', '', '', '<p><span style="font-weight: 400;" data-mce-style="font-weight: 400;">Made from Ayam Nanas dan dibalut breadcumb yang renyah, menjadikan </span><b>Ayam Nanas Chicken Katsu</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> menjadi pilihan kaya protein yang lezat dan praktis.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/ayam-nanas/AyamNanas-EasyToCook-Katsu.png?_t=1773300336', '', '', 1, 3, 1, 'admin', '2026-03-10 18:19:42', '2026-03-10 18:19:42'),
	(61, 9, 'Belfoods Chicken Nugget Crunchy', 'belfoods-chicken-nugget-crunchy.html', 'Belfoods Chicken Nugget Crunchy', '', 'Net Weight: 250gr | 500gr | 1000gr', '', '', '', '', '<p><b>Belfoods Nugget Ayam Crunchy</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> menghadirkan sajian Favorit bagi seluruh keluarga. Made from daging ayam pilihan dibalut dengan tepung bumbu berbentuk bubble, menghadirkan sensasi renyah di setiap gigitan. Renyahnya </span><b>Belfoods Nugget Ayam Crunchy</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> membawa keceriaan di setiap momen bersama keluarga.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-NuggetCrunchy-450gr.png?_t=1773218384', '', '', 1, 1, 1, 'admin', '2026-03-11 15:47:14', '2026-03-11 15:47:14'),
	(62, 9, 'Belfoods Chicken Nugget Crunchy Stick', 'belfoods-chicken-nugget-crunchy-stick.html', 'Belfoods Chicken Nugget Crunchy Stick', '', 'Net Weight: 170gr  |  450gr ', '', '', '', '', '<p><b>Belfoods Nugget Ayam Stick Crunchy</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> menghadirkan sajian Favorit bagi seluruh keluarga. Made from daging ayam pilihan dibalut dengan tepung bumbu berbentuk bubble, menghadirkan sensasi renyah di setiap gigitan. Renyahnya </span><b>Belfoods Nugget Ayam Stick Crunchy</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> membawa keceriaan di setiap momen bersama keluarga.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-NuggetCrunchyStick-450gr.png', '', '', 1, 2, 1, 'admin', '2026-03-11 15:50:43', '2026-03-11 15:50:43'),
	(63, 9, 'Belfoods Chicken Nugget Cornflakes', 'belfoods-chicken-nugget-cornflakes.html', 'Belfoods Chicken Nugget Cornflakes', '', 'Net Weight: 120gr  |  450gr', '', '', '', '', '<p><b>Belfoods Nugget Ayam Cornflakes </b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">menghadirkan sajian Favorit bagi seluruh keluarga. Made from daging ayam pilihan dibalut dengan Cornflakes yang renyah, menghadirkan sensasi renyah di setiap gigitan. Renyahnya </span><b>Belfoods Nugget Ayam Cornflakes </b><span style="font-weight: 400;" data-mce-style="font-weight: 400;">membawa keceriaan di setiap momen bersama keluarga.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-NuggetCornflakes-450g.png', '', '', 1, 3, 1, 'admin', '2026-03-11 15:52:21', '2026-03-11 15:52:21'),
	(64, 9, 'Belfoods Chicken Nugget Ã¢â¬ÅSÃ¢â¬Â', 'belfoods-chicken-nugget-s.html', 'Belfoods Chicken Nugget Ã¢â¬ÅSÃ¢â¬Â', '', 'Net Weight: 170gr', '', '', '', '', '<p><b>Belfoods Chicken Nugget Bentuk S</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> menghadirkan sajian favorit bagi seluruh keluarga. Dibuat dengan daging ayam pilihan dan dilapisi tepung roti yang gurih dan renyah, </span><b>Belfoods Chicken Nugget Bentuk S</b><span style="font-weight: 400;" data-mce-style="font-weight: 400;"> hadirkan keceriaan di segala suasana keluarga Anda.</span></p>', '', '2019-01-01 00:00:00', 'https://belfoods.com/id/public/products/belfoods/Belfoods-Nugget-S-170gr.png', '', '', 1, 9, 1, 'admin', '2026-03-11 15:57:08', '2026-03-11 15:57:08'),
