	(169, 'orderNow', 'https://belfoods.com/id/order', '<b>Shop Now!</b>', 'Add Text 2 Here !', 'Add Text 3 Here !', 'Add Text 4 Here !', '', '<p>Add Content Here !</p>', 0, 1, '2017-01-01 00:00:00', '2026-03-18 15:25:31'),
	(170, 'bannerAds', '', 'Add Text 1 Here !', 'Add Text 2 Here !', 'Add Text 3 Here !', 'Add Text 4 Here !', '', 'Add Content Here !', 0, 1, '2017-01-01 00:00:00', '2017-01-01 00:00:00'),
	(171, 'bannerAds', '', 'Add Text 1 Here !', 'Add Text 2 Here !', 'Add Text 3 Here !', 'Add Text 4 Here !', '', 'Add Content Here !', 0, 1, '2017-01-01 00:00:00', '2017-01-01 00:00:00'),
	(173, 'widgetAbout', '', '<b>Belfoods Berasal Dari Yang Terbaik</b>', 'Add Text 2 Here !', 'Add Text 3 Here !', 'Add Text 4 Here !', 'https://belfoods.com/id/public/content/Kenapa-Belfoods-1.png?_t=1774587767', '<p style="line-height: 1.3; text-align: justify;" data-mce-style="line-height: 1.3; text-align: justify;">PT Belfoods Indonesia merupakan bagian dari PT Sreeya Sewu Indonesia, Tbk yang memiliki bisnis yang terintegrasi dari perternakan hingga pengolahan ayam, sehingga dapat mengontrol bahan baku daging ayam yang berkualitas dan berstandar tinggi juga bersertifikasi <strong>HALAL dari MUI</strong>.</p>', 0, 1, '2017-01-01 00:00:00', '2026-04-02 11:16:54'),
	(174, 'widgetAbout', '', '<b>Belfoods Diproses Secara Higienis</b>', 'Add Text 2 Here !', 'Add Text 3 Here !', 'Add Text 4 Here !', 'https://belfoods.com/id/public/content/Kenapa-Belfoods-2.png?_t=1774605247', '<p style="line-height: 1.3; text-align: justify;" data-mce-style="line-height: 1.3; text-align: justify;">Proses pembuatan Belfoods juga telah di control dengan sangat ketat dan bersertifikasi <strong>ISO 22000</strong> dan <strong>ISO 9001</strong>, sehingga menjamin untuk menghasilkan produk yang berkualitas, aman dan juga higienis.</p>', 0, 1, '2017-01-01 00:00:00', '2026-04-02 11:16:46'),
	(175, 'widgetAbout', '', '<b>Belfoods Lezatnya Cinta Ibu</b>', 'Add Text 2 Here !', 'Add Text 3 Here !', 'Add Text 4 Here !', 'https://belfoods.com/id/public/content/Kenapa-Belfoods-3.png?_t=1774607728', '<p style="line-height: 1.3; text-align: justify;" data-mce-style="line-height: 1.3; text-align: justify;">Kelezatan, kerenyahan, dan rasa yang istimewa adalah ciri khas dari produk Belfoods. Produk-produk Belfoods tersedia dalam berbagai varian, seperti naget, sosis, bakso, dan varian olahan ayam lainnya. Belfoods cocok disajikan sebagai hidangan lauk pendamping nasi ataupun camilan, bisa dinikmati kapan saja dan dimana saja.</p>', 0, 1, '2017-01-01 00:00:00', '2026-04-02 11:16:37'),
	(176, 'onlineShop', 'https://www.blibli.com/brand/belfoods-official-store', 'Add Text 1 Here !', 'Add Text 2 Here !', 'Add Text 3 Here !', 'Add Text 4 Here !', 'https://belfoods.com/wp-content/uploads/2022/02/01-BliBli_1024x355.png', 'Add Content Here !', 7, 1, '2017-01-01 00:00:00', '2026-03-06 18:32:55'),
